command:
$ErrorActionPreference = 'Stop'
Set-StrictMode -Version 2.0
$repo = $env:DCOIR_REPO_ROOT
if ([string]::IsNullOrWhiteSpace($repo)) { $repo = $env:GITHUB_WORKSPACE }
if ([string]::IsNullOrWhiteSpace($repo) -or -not (Test-Path -LiteralPath $repo -PathType Container)) { throw 'Unable to resolve repository root.' }
$branch = 'implement-pr-review-command-workflow'
$expectedHead = '34218ee2327e20e93006ce52c5ff7f2265620987'
$requestId = 'exec-20260619-pr281-quoted-auth-redaction-004'
$payload = Join-Path $repo 'chatgpt_staging/exec_payloads/pr281_quoted_auth_redaction_patch_003.py'
$expectedPaths = @('scripts/openrouter_pr_review.py', 'scripts/openrouter_pr_review_selftest.py')
$expectedBlobs = @{
  'scripts/openrouter_pr_review.py' = 'b10e839f3ede7de1b24c00f918228fa7585fd484'
  'scripts/openrouter_pr_review_selftest.py' = 'd5f56ba3f575129976899191a5f9575b5a15ba09'
}
function Invoke-GitChecked([string]$Cwd, [string[]]$Args) {
  $out = & git -C $Cwd @Args 2>&1
  if ($LASTEXITCODE -ne 0) { throw "git $($Args -join ' ') failed with exit code $LASTEXITCODE`n$out" }
  return $out
}
function Get-GitText([string]$Cwd, [string[]]$Args) { return ((Invoke-GitChecked -Cwd $Cwd -Args $Args | Out-String).Trim()) }
function Invoke-NativeChecked([string]$Exe, [string[]]$Args, [string]$Label) {
  $out = & $Exe @Args 2>&1
  if ($LASTEXITCODE -ne 0) { throw "$Label failed with exit code $LASTEXITCODE`n$out" }
  return $out
}
if (-not (Test-Path -LiteralPath $payload -PathType Leaf)) { throw "Patch payload not found: $payload" }
Invoke-GitChecked $repo @('fetch','origin',"+refs/heads/${branch}:refs/remotes/origin/${branch}") | Out-Null
$remoteHead = Get-GitText $repo @('rev-parse',"origin/$branch")
if ($remoteHead -ne $expectedHead) { throw "PR branch head mismatch. Expected $expectedHead but got $remoteHead." }
$tempRoot = $env:RUNNER_TEMP
if ([string]::IsNullOrWhiteSpace($tempRoot)) { $tempRoot = [IO.Path]::GetTempPath() }
$worktree = Join-Path $tempRoot $requestId
if (Test-Path -LiteralPath $worktree) { Remove-Item -LiteralPath $worktree -Recurse -Force }
Invoke-GitChecked $repo @('worktree','prune') | Out-Null
Invoke-GitChecked $repo @('worktree','add','--detach',$worktree,"origin/$branch") | Out-Null
try {
  foreach ($path in $expectedPaths) {
    $line = Get-GitText $worktree @('ls-files','-s','--',$path)
    $blob = (($line -split '\s+')[1])
    if ($blob -ne $expectedBlobs[$path]) { throw "Blob mismatch for $path. Expected $($expectedBlobs[$path]) but got $blob." }
  }
  Invoke-NativeChecked 'python' @($payload, $worktree) 'Patch payload' | Out-Null
  Invoke-NativeChecked 'python' @('-m','py_compile',(Join-Path $worktree 'scripts/openrouter_pr_review.py'),(Join-Path $worktree 'scripts/openrouter_pr_review_selftest.py')) 'py_compile' | Out-Null
  Invoke-NativeChecked 'python' @((Join-Path $worktree 'scripts/openrouter_pr_review_selftest.py')) 'offline selftest' | Out-Null
  Invoke-GitChecked $worktree @('diff','--check','--') | Out-Null
  Invoke-GitChecked $worktree @('config','user.name','github-actions[bot]') | Out-Null
  Invoke-GitChecked $worktree @('config','user.email','41898282+github-actions[bot]@users.noreply.github.com') | Out-Null
  Invoke-GitChecked $worktree (@('add','--') + $expectedPaths) | Out-Null
  Invoke-GitChecked $worktree @('diff','--cached','--check') | Out-Null
  $changedText = Get-GitText $worktree @('diff','--cached','--name-only')
  $changedPaths = @($changedText -split "`r?`n" | Where-Object { -not [string]::IsNullOrWhiteSpace($_) })
  $unexpected = @($changedPaths | Where-Object { $expectedPaths -notcontains $_ })
  $missing = @($expectedPaths | Where-Object { $changedPaths -notcontains $_ })
  if ($unexpected.Count -gt 0) { throw "Unexpected changed paths: $($unexpected -join ', ')" }
  if ($missing.Count -gt 0) { throw "Expected changed paths missing: $($missing -join ', ')" }
  Invoke-GitChecked $worktree @('commit','-m','Redact quoted auth scheme tokens') | Out-Null
  $newHead = Get-GitText $worktree @('rev-parse','HEAD')
  $token = $env:DCOIR_GITHUB_FG_TOKEN
  if ([string]::IsNullOrWhiteSpace($token)) { $token = $env:DCOIR_GITHUB_CL_TOKEN }
  if ([string]::IsNullOrWhiteSpace($token)) { throw 'No bridged GitHub token secret is available for PR branch push.' }
  Write-Host "::add-mask::$token"
  $repoFull = $env:GITHUB_REPOSITORY
  if ([string]::IsNullOrWhiteSpace($repoFull)) { $repoFull = 'DCOIR-Collector/dcoir-collector' }
  $pushUrl = "https://x-access-token:${token}@github.com/${repoFull}.git"
  Invoke-GitChecked $worktree @('-c','http.https://github.com/.extraheader=','push',$pushUrl,"HEAD:refs/heads/$branch") | Out-Null
  $summaryDir = Join-Path $repo "chatgpt_staging/status_reports/chatgpt-exec/$requestId"
  New-Item -ItemType Directory -Force -Path $summaryDir | Out-Null
  [ordered]@{
    schema = 'dcoir.chatgpt_exec.pr281_quoted_auth_redaction.v1'
    request_id = $requestId
    result = 'success'
    branch = $branch
    starting_head = $expectedHead
    new_head = $newHead
    changed_paths = $changedPaths
    validations = @('branch_head_guard','blob_guards','patch_payload','py_compile','offline_selftest','diff_check','changed_path_guard','push')
    targeted_thread = 'PRRT_kwDOR0OHZ86Kzfst'
    created_utc = (Get-Date).ToUniversalTime().ToString('yyyy-MM-ddTHH:mm:ssZ')
  } | ConvertTo-Json -Depth 6 | Out-File -FilePath (Join-Path $summaryDir 'pr281_quoted_auth_redaction_summary.json') -Encoding utf8
  @(
    '# PR #281 quoted auth redaction summary',
    '',
    '- result: success',
    "- branch: $branch",
    "- starting_head: $expectedHead",
    "- new_head: $newHead",
    "- changed_paths: $($changedPaths -join ', ')",
    '- targeted_thread: PRRT_kwDOR0OHZ86Kzfst',
    '- validation: branch head guard; blob guards; patch payload; py_compile; offline selftest; diff checks; changed-path guard; push',
    '',
    'Summary: hardened Authorization and Proxy-Authorization auth-scheme redaction so quoted tokens after Bearer, Basic, and token are consumed as part of the credential while exact safe references remain preserved.'
  ) | Out-File -FilePath (Join-Path $summaryDir 'pr281_quoted_auth_redaction_summary.md') -Encoding utf8
  Write-Host "new_head=$newHead"
}
finally {
  if (Test-Path -LiteralPath $worktree) {
    try { Invoke-GitChecked $repo @('worktree','remove','--force',$worktree) | Out-Null } catch { Write-Warning "Unable to remove worktree ${worktree}: $($_.Exception.Message)" }
  }
}
